import{C as s,o as r,c as n,a5 as a,E as o}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"5. QUIC & Fiber (network details)","description":"","frontmatter":{},"headers":[],"relativePath":"module-5/5-quic-fiber.md","filePath":"module-5/5-quic-fiber.md","lastUpdated":1780937944000}'),l={name:"module-5/5-quic-fiber.md"},k=Object.assign(l,{setup(p){const i={id:"m5-5-quic-fiber",title:"🧠 Mini-check: QUIC & Fiber",intro:"2 питання.",questions:[{type:"mcq",q:"QUIC vs TCP для Solana TPU?",options:["QUIC: UDP-based з reliability + multiplexing built-in","Lower handshake latency (0-RTT for repeat connections)","Better congestion control під validator load","TCP simpler але higher latency per connection"],correct:[0,1,2,3],explanation:"Все правильно. Module 5.5."},{type:"explain",q:"Що таке Fiber protocol і чому important для Solana scaling?",ideal:`Fiber — newer agave networking layer optimized для validator-to-validator traffic. Replaces older socket-based approach з kernel-bypass technology (DPDK-similar).

Key aspects:
1. Kernel bypass: packets go directly до NIC через user-space drivers, skipping kernel network stack. Reduces latency 10-100x for high-throughput traffic.

2. Specifically designed для UDP multicast (turbine traffic). Standard kernel sockets struggle з millions of packets/sec.

3. Reduces CPU overhead — handling packets у kernel uses cycles. Fiber moves це до user-space efficient processing.

4. Required для achieving Firedancer-level throughput у agave.

Why important: Solana wants 1M+ TPS long-term. Standard kernel networking caps significantly lower. Fiber removes major bottleneck.

For operators: requires specific NIC support (Intel NICs з DPDK), kernel configuration. Not all hosting providers support. Currently optional, eventually may become mandatory для top-tier performance.`,explanation:"Module 5.5."}]};return(d,e)=>{const t=s("Quiz");return r(),n("div",null,[e[0]||(e[0]=a(`<h1 id="_5-quic-fiber-network-details" tabindex="-1">5. QUIC &amp; Fiber (network details) <a class="header-anchor" href="#_5-quic-fiber-network-details" aria-label="Permalink to &quot;5. QUIC &amp; Fiber (network details)&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>QUIC</strong> — modern transport protocol used by Solana TPU. UDP-based з TCP-like reliability + multiplexing. Lower latency than TCP, better congestion control.</p><p><strong>Fiber</strong> — newer agave networking layer using kernel-bypass для high-performance turbine. Critical для achieving high TPS, requires specific NIC support.</p><h2 id="quic-у-solana" tabindex="-1">QUIC у Solana <a class="header-anchor" href="#quic-у-solana" aria-label="Permalink to &quot;QUIC у Solana&quot;">​</a></h2><p>Старі validator versions used TCP / raw UDP. Switched до QUIC ~2023 для improvements:</p><h3 id="quic-properties" tabindex="-1">QUIC properties <a class="header-anchor" href="#quic-properties" aria-label="Permalink to &quot;QUIC properties&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>TCP</th><th>UDP raw</th><th>QUIC</th></tr></thead><tbody><tr><td>Reliable delivery</td><td>✅</td><td>❌</td><td>✅</td></tr><tr><td>Multiple streams</td><td>❌ (one stream per connection)</td><td>❌</td><td>✅</td></tr><tr><td>Built-in encryption</td><td>❌</td><td>❌</td><td>✅ (TLS 1.3)</td></tr><tr><td>Handshake latency</td><td>1-RTT minimum</td><td>0</td><td>0-RTT for repeat</td></tr><tr><td>Connection migration</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>User-space implementation</td><td>Mostly kernel</td><td>User OK</td><td>User-space</td></tr></tbody></table><h3 id="solana-use-case" tabindex="-1">Solana use case <a class="header-anchor" href="#solana-use-case" aria-label="Permalink to &quot;Solana use case&quot;">​</a></h3><p>TPU (incoming TXs) використовує QUIC для:</p><ul><li><strong>Many concurrent senders</strong>: clients submit TXs concurrently. QUIC multiplexing handles efficiently.</li><li><strong>Reliability</strong>: TX submission shouldn&#39;t be lost</li><li><strong>Encryption</strong>: built-in TLS protects від MitM</li><li><strong>Connection efficiency</strong>: 0-RTT для repeat senders (apps re-sending many TXs)</li></ul><h3 id="stake-weighted-quic" tabindex="-1">Stake-weighted QUIC <a class="header-anchor" href="#stake-weighted-quic" aria-label="Permalink to &quot;Stake-weighted QUIC&quot;">​</a></h3><p>Solana added enhancement: validators prioritize QUIC connections from <strong>other validators</strong> based on stake. Anti-spam mechanism — random clients can DoS via TPU, stake-weighted prioritization protects validator.</p><p>Reserved bandwidth для known stake-holders.</p><h2 id="fiber-protocol" tabindex="-1">Fiber protocol <a class="header-anchor" href="#fiber-protocol" aria-label="Permalink to &quot;Fiber protocol&quot;">​</a></h2><p>Recently introduced (~2024-2025) у agave: kernel-bypass networking layer для turbine traffic.</p><h3 id="why-kernel-networking-insufficient" tabindex="-1">Why kernel networking insufficient <a class="header-anchor" href="#why-kernel-networking-insufficient" aria-label="Permalink to &quot;Why kernel networking insufficient&quot;">​</a></h3><p>Standard Linux network stack:</p><ol><li>Packet arrives NIC → kernel network stack</li><li>Кернель processes (firewall, routing, протоколи)</li><li>Copies to user-space (validator process)</li><li>Validator processes</li></ol><p>Each packet: ~10-50 microseconds overhead. Mainnet ~5000 packets/sec turbine receive = significant CPU.</p><p>Future scaling (Firedancer goals, Alpenglow throughput) — kernel becomes bottleneck.</p><h3 id="fiber-approach" tabindex="-1">Fiber approach <a class="header-anchor" href="#fiber-approach" aria-label="Permalink to &quot;Fiber approach&quot;">​</a></h3><p>Kernel bypass:</p><ol><li>Packet arrives NIC → directly до user-space (skip kernel)</li><li>Validator processes inline (low latency)</li></ol><p>Requires:</p><ul><li><strong>Compatible NIC</strong> (Intel NICs з DPDK support зазвичай)</li><li><strong>Hugepages</strong> (large memory pages для efficient buffering)</li><li><strong>CPU affinity</strong> (specific cores dedicated до networking)</li><li><strong>Special agave build/flags</strong></li></ul><p>Performance gain: 10-100x packet processing throughput vs kernel networking.</p><h3 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h3><p>Currently optional у agave. Activated through specific flags:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">agave-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --enable-fiber</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --fiber-config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/fiber.toml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [other </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">flags]</span></span></code></pre></div><p>Many validators don&#39;t use yet (complexity, NIC requirements). Adoption growing.</p><p>Firedancer uses similar approach by default.</p><h2 id="tcp-based-ports-still-exist" tabindex="-1">TCP-based ports (still exist) <a class="header-anchor" href="#tcp-based-ports-still-exist" aria-label="Permalink to &quot;TCP-based ports (still exist)&quot;">​</a></h2><p>Не все Solana traffic over QUIC/Fiber:</p><ul><li><strong>RPC</strong> (port 8899): standard HTTP over TCP</li><li><strong>WebSocket</strong> (port 8900): WebSocket over TCP</li><li><strong>Gossip</strong> (port 8001): primarily UDP, gossip-specific protocol</li></ul><p>QUIC specifically для TPU. Fiber для turbine.</p><h2 id="operator-considerations" tabindex="-1">Operator considerations <a class="header-anchor" href="#operator-considerations" aria-label="Permalink to &quot;Operator considerations&quot;">​</a></h2><h3 id="standard-setup-no-fiber" tabindex="-1">Standard setup (no Fiber) <a class="header-anchor" href="#standard-setup-no-fiber" aria-label="Permalink to &quot;Standard setup (no Fiber)&quot;">​</a></h3><p>Most validators run без Fiber:</p><ul><li>Standard Ubuntu kernel</li><li>Standard NICs</li><li>agave default networking</li><li>Adequate performance для mainnet currently</li></ul><h3 id="performance-setup-з-fiber" tabindex="-1">Performance setup (з Fiber) <a class="header-anchor" href="#performance-setup-з-fiber" aria-label="Permalink to &quot;Performance setup (з Fiber)&quot;">​</a></h3><p>High-end operators:</p><ul><li>Intel NICs (X710, X550, E810 series)</li><li>Hugepages configured</li><li>Fiber enabled via config</li><li>10Gbps+ network</li></ul><p>Cost trade-off: more setup complexity, hardware requirements vs incremental performance gains.</p><h3 id="recommendation-для-lumlabs" tabindex="-1">Recommendation для LumLabs <a class="header-anchor" href="#recommendation-для-lumlabs" aria-label="Permalink to &quot;Recommendation для LumLabs&quot;">​</a></h3><p>For now: standard setup, focus on hardware fundamentals (CPU, RAM, NVMe). Fiber experimentation после mainnet performance optimization needs justify additional complexity.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="verify-quic-active" tabindex="-1">Verify QUIC active <a class="header-anchor" href="#verify-quic-active" aria-label="Permalink to &quot;Verify QUIC active&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Validator logs mention QUIC connections</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quic</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Network connections — TPU port (8003 typical) should show QUIC traffic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -unap</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;:8003&quot;</span></span></code></pre></div><h3 id="monitor-network-performance" tabindex="-1">Monitor network performance <a class="header-anchor" href="#monitor-network-performance" aria-label="Permalink to &quot;Monitor network performance&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Packet rate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> netstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Look for high packet rates без errors</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Network errors</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> link</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Look for drops/errors</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,52)),o(t,{data:i}),e[1]||(e[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#q"><code>QUIC</code></a>, <a href="/glossary#f"><code>Fiber</code></a>, <a href="/glossary#k"><code>Kernel bypass</code></a>, <a href="/glossary#d"><code>DPDK</code></a>, <a href="/glossary#s"><code>Stake-weighted QUIC</code></a>, <a href="/glossary#h"><code>Hugepages</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/validator/quic" target="_blank" rel="noreferrer">Anza: QUIC implementation</a></li><li><a href="https://www.cloudflare.com/learning/performance/what-is-http3/" target="_blank" rel="noreferrer">QUIC protocol overview</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-5/4-repair">← 4. Repair</a></p>',6))])}}});export{c as __pageData,k as default};
